fixed_code:
use std::iter;

struct MyCollection<T> {
    items: Vec<T>,
}

impl<T> Extend<T> for MyCollection<T> {
    fn extend<I>(&mut self, iter: I)
    where
        I: IntoIterator<Item = T>,
    {
        for item in iter {
            self.items.push(item);
        }
    }
}

impl<T> FromIterator<T> for MyCollection<T> {
    fn from_iter<I>(iter: I) -> Self
    where
        I: IntoIterator<Item = T>,
    {
        let mut coll = MyCollection { items: Vec::new() };
        coll.extend(iter);
        coll
    }
}

fn main() {
    let mut coll = MyCollection { items: vec![] };
    for i in 0..5 {
        coll.extend((1..=i).collect::<Vec<_>>());
    }
    println!("{:?}", coll.items);
}

